# Base utility module providing foundational classes and functions

class Counter:
    count: int

    def __init__(self, start: int = 0):
        self.count = start

    @virtual
    def increment(self) -> int:
        self.count += 1
        return self.count

    def get_count(self) -> int:
        return self.count

class Accumulator:
    total: int

    def __init__(self):
        self.total = 0

    def add(self, value: int) -> int:
        self.total += self.total + value
        return self.total

def double_value(x: int) -> int:
    return x * 2

def calculate_average(values: list[int]) -> float:
    if len(values) == 0:
        return 0.0
    sum_val: int = sum(values)
    return float(sum_val) / float(len(values))

