# Advanced utilities that extend base functionality
from base_utils import Counter, Accumulator

class StepCounter(Counter):
    step_size: int

    def __init__(self, start: int, step: int):
        super().__init__(start)
        self.step_size = step

    @override
    def increment(self) -> int:
        self.count += self.step_size
        return self.count

class RollingAccumulator(Accumulator):
    history: list[int]
    max_history: int

    def __init__(self, max_history: int = 5):
        super().__init__()
        self.history = []
        self.max_history = max_history

    @override
    def add(self, value: int) -> int:
        result: int = super().add(value)
        self.history.append(result)
        if len(self.history) > self.max_history:
            self.history.pop(0)
        return result

    def get_history(self) -> list[int]:
        return self.history.copy()

def scale_and_offset(value: int, scale: int, offset: int) -> int:
    return value * scale + offset
